from flask import Flask, request, jsonify

app = Flask(__name__)

users = {
    1: {'username': 'john_doe', 'email': 'john_doe@example.com', 'role': 'user', 'account_status': 'active', 'subscription_tier': 'free'},
    2: {'username': 'jane_smith', 'email': 'jane_smith@example.com', 'role': 'moderator', 'account_status': 'active', 'subscription_tier': 'pro'}
}

@app.route('/api/users/<int:user_id>', methods=['PUT'])
def update_user(user_id):
    current_user = 1  # Assuming current admin user is user with ID 1
    if current_user != 1:
        return jsonify({'error': 'Unauthorized access'}), 401

    if user_id not in users:
        return jsonify({'error': 'User not found'}), 404

    data = request.get_json()
    if 'email' in data:
        users[user_id]['email'] = data['email']
    if 'username' in data:
        users[user_id]['username'] = data['username']
    if 'role' in data:
        users[user_id]['role'] = data['role']
    if 'account_status' in data:
        users[user_id]['account_status'] = data['account_status']
    if 'subscription_tier' in data:
        users[user_id]['subscription_tier'] = data['subscription_tier']

    return jsonify({'message': 'User updated successfully', 'user': users[user_id]})

